                self.pending
                    .entry(id)
                    .and_modify(|existing| {
                        existing.count = existing.count.saturating_add(ba.count);
                        if ba.last_ts > existing.last_ts {
                            existing.last_ts = ba.last_ts;
                        }
                    })
